sql:
SELECT COUNT(DISTINCT guest_id) 
FROM appearance_history 
WHERE appearance_count > 1;

SELECT COUNT(guest_id) 
FROM guest_groups 
WHERE group_id = 0;

external_knowledge:
- "graced the stage" refers to the number of times a guest has appeared on a show;
- "average starlight" refers to the average rating of the shows;
- "chorus of voices" refers to the total number of reviews for the shows;
- "shone the brightest" refers to the guests with the highest number of appearances.

- 'appearances' refers to the number of times a guest has appeared on any show;
- 'groups' are organizations or associations the guest is a part of;
- 'average rating' is the mean rating of the shows a guest has appeared in.

sql:
SELECT guest_id, show_id, appearance_date, appearance_count
FROM appearance_history
WHERE appearance_count > 1 AND appearance_date = '1999-01-12';

SELECT MAX(appearance_count) AS most_appearances
FROM (
    SELECT guest_id, COUNT(appearance_id) AS appearance_count
    FROM appearances
    GROUP BY guest_id
);

